import jwt
import json
from typing import Dict, Any, Optional

def decode_jwt(token: str, secret: Optional[str] = None, algorithms: list = ['HS256']) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes
    
    Args:
        token (str): The JWT token to decode
        secret (str, optional): The secret used to sign the token
        algorithms (list): List of allowed algorithms
    
    Returns:
        dict: Decoded token payload
    """
    try:
        # Decode without verification first to see the structure
        decoded = jwt.decode(token, options={"verify_signature": False})
        print("Token structure:")
        print(json.dumps(decoded, indent=2, default=str))
        
        # Verify the token if secret is provided
        if secret:
            verified = jwt.decode(token, secret, algorithms=algorithms)
            print("\nVerified token contents:")
            print(json.dumps(verified, indent=2, default=str))
            return verified
        else:
            print("\nNo secret provided - token verified with options={\"verify_signature\": False}")
            return decoded
            
    except jwt.ExpiredSignatureError:
        print("Token has expired")
        return {"error": "expired"}
    except jwt.InvalidTokenError as e:
        print(f"Invalid token: {e}")
        return {"error": str(e)}
    except Exception as e:
        print(f"Error decoding token: {e}")
        return {"error": str(e)}

def inspect_jwt(token: str) -> None:
    """
    Quick inspection of JWT token without verification
    
    Args:
        token (str): The JWT token to inspect
    """
    try:
        # Split the token to get header and payload
        header, payload, signature = token.split('.')
        
        # Decode header
        import base64
        header_decoded = base64.urlsafe_b64decode(header + '=' * (4 - len(header) % 4))
        print("Header:")
        print(json.dumps(json.loads(header_decoded), indent=2))
        
        # Decode payload
        payload_decoded = base64.urlsafe_b64decode(payload + '=' * (4 - len(payload) % 4))
        print("\nPayload:")
        print(json.dumps(json.loads(payload_decoded), indent=2))
        
    except Exception as e:
        print(f"Error inspecting token: {e}")